using Store;

namespace Store.Tests;

[TestClass]
public sealed class ShoppingCartTests
{
    private ShoppingCart _cart = null!;

    [TestInitialize]
    public void Setup() => _cart = new ShoppingCart();

    // ── AddItem ──────────────────────────────────────────────

    [TestMethod]
    public void AddItem_SingleItem_IncreasesTotal()
    {
        _cart.AddItem("SKU-1", 2, 9.99m);

        Assert.AreEqual(19.98m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_MultipleDistinctItems_SumsCorrectly()
    {
        _cart.AddItem("A", 1, 10m);
        _cart.AddItem("B", 3, 5m);

        Assert.AreEqual(25m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_SameSkuTwice_CombinesQuantity()
    {
        _cart.AddItem("A", 1, 10m);
        _cart.AddItem("A", 2, 10m);

        Assert.AreEqual(30m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_NullSku_Throws()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _cart.AddItem(null!, 1, 5m));
    }

    [TestMethod]
    public void AddItem_EmptySku_Throws()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _cart.AddItem("", 1, 5m));
    }

    [TestMethod]
    public void AddItem_ZeroQuantity_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _cart.AddItem("A", 0, 5m));
    }

    [TestMethod]
    public void AddItem_NegativeQuantity_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _cart.AddItem("A", -1, 5m));
    }

    [TestMethod]
    public void AddItem_NegativePrice_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _cart.AddItem("A", 1, -1m));
    }

    [TestMethod]
    public void AddItem_ZeroPrice_Succeeds()
    {
        _cart.AddItem("FREE", 1, 0m);

        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    // ── RemoveItem ───────────────────────────────────────────

    [TestMethod]
    public void RemoveItem_ExistingItem_RemovesFromTotal()
    {
        _cart.AddItem("A", 1, 10m);
        _cart.AddItem("B", 1, 20m);

        _cart.RemoveItem("A");

        Assert.AreEqual(20m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void RemoveItem_OnlyItem_TotalIsZero()
    {
        _cart.AddItem("A", 5, 3m);

        _cart.RemoveItem("A");

        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void RemoveItem_NonExistentSku_ThrowsKeyNotFound()
    {
        Assert.ThrowsException<KeyNotFoundException>(
            () => _cart.RemoveItem("MISSING"));
    }

    [TestMethod]
    public void RemoveItem_NullSku_Throws()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _cart.RemoveItem(null!));
    }

    // ── CalculateTotal ───────────────────────────────────────

    [TestMethod]
    public void CalculateTotal_EmptyCart_ReturnsZero()
    {
        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_AfterAddAndRemove_ReflectsChanges()
    {
        _cart.AddItem("A", 2, 10m);
        _cart.AddItem("B", 1, 5m);
        _cart.RemoveItem("B");

        Assert.AreEqual(20m, _cart.CalculateTotal());
    }

    // ── ApplyCoupon ──────────────────────────────────────────

    [TestMethod]
    public void ApplyCoupon_Save10_Applies10PercentDiscount()
    {
        _cart.AddItem("A", 1, 100m);

        _cart.ApplyCoupon("SAVE10");

        Assert.AreEqual(90m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_Save20_Applies20PercentDiscount()
    {
        _cart.AddItem("A", 1, 100m);

        _cart.ApplyCoupon("SAVE20");

        Assert.AreEqual(80m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_Half_Applies50PercentDiscount()
    {
        _cart.AddItem("A", 1, 100m);

        _cart.ApplyCoupon("HALF");

        Assert.AreEqual(50m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_CaseInsensitive()
    {
        _cart.AddItem("A", 1, 100m);

        _cart.ApplyCoupon("save10");

        Assert.AreEqual(90m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_UnknownCode_Throws()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _cart.ApplyCoupon("BOGUS"));
    }

    [TestMethod]
    public void ApplyCoupon_NullCode_Throws()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _cart.ApplyCoupon(null!));
    }

    [TestMethod]
    public void ApplyCoupon_SecondCouponOverridesFirst()
    {
        _cart.AddItem("A", 1, 100m);
        _cart.ApplyCoupon("SAVE10");
        _cart.ApplyCoupon("SAVE20");

        Assert.AreEqual(80m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_OnEmptyCart_TotalRemainsZero()
    {
        _cart.ApplyCoupon("HALF");

        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    // ── Integration / combined scenarios ─────────────────────

    [TestMethod]
    public void FullWorkflow_AddRemoveCouponTotal()
    {
        _cart.AddItem("A", 2, 50m);   // 100
        _cart.AddItem("B", 1, 30m);   // 30
        _cart.RemoveItem("B");         // 100
        _cart.ApplyCoupon("SAVE10");   // 90

        Assert.AreEqual(90m, _cart.CalculateTotal());
    }
}

